PRAGMA foreign_keys = ON;CREATE TABLE IF NOT EXISTS users (  id INTEGER PRIMARY KEY AUTOINCREMENT,  username TEXT NOT NULL UNIQUE,  password_hash TEXT NOT NULL,  created_at TEXT NOT NULL DEFAULT (datetime('now')));CREATE TABLE IF NOT EXISTS loans (  id INTEGER PRIMARY KEY AUTOINCREMENT,  client_name TEXT NOT NULL,  rate_bps INTEGER NOT NULL,              -- tasa en "basis points": 20% => 2000  status TEXT NOT NULL DEFAULT 'active',  -- active | liquidated  created_at TEXT NOT NULL DEFAULT (datetime('now')),  liquidated_at TEXT);CREATE TABLE IF NOT EXISTS loan_months (  id INTEGER PRIMARY KEY AUTOINCREMENT,  loan_id INTEGER NOT NULL,  month_date TEXT NOT NULL,               -- YYYY-MM-01 (primer día del mes)  capital_cents INTEGER NOT NULL,  interest_cents INTEGER NOT NULL,  total_cents INTEGER NOT NULL,  payment_cents INTEGER NOT NULL DEFAULT 0,  created_at TEXT NOT NULL DEFAULT (datetime('now')),  FOREIGN KEY (loan_id) REFERENCES loans(id) ON DELETE CASCADE);CREATE INDEX IF NOT EXISTS idx_loan_months_loan_id ON loan_months(loan_id);CREATE UNIQUE INDEX IF NOT EXISTS uq_loan_months_loan_month ON loan_months(loan_id, month_date);
